insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('7ab2e6fc-b8fe-5c93-9084-22c2907ae915', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Shockwave', 'You’ll be graded on two things: the outcome for Halcyon Air, and your leadership through the process. The openness of the team you walk in with is set by the trust you’ve earned before.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds, difficulty) values ('7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'solo', '{"cash":{"label":"Cash on hand","val":58,"min":0,"max":90},"board":{"label":"Board confidence","val":62,"min":0,"max":100},"morale":{"label":"Workforce morale","val":64,"min":0,"max":100},"trust":{"label":"Public trust","val":57,"min":0,"max":100}}'::jsonb, 4, 255, 1.03);
insert into documents (id, scenario_id, key, title, meta, body_json) values ('a365a91b-639e-522a-9902-7949a9890df0', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'solo_content', 'Shockwave — engine content', '{"type":"solo_content","slug":"shockwave","captured_fns":12}'::jsonb, '{"CONFIG":{"weekSeconds":255,"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6},"COMPANY":{"name":"Halcyon Air","sub":"Regional carrier · 4,200 employees · 38 aircraft","logo":"H"},"DRIVERS":{"cash":{"label":"Cash on hand","unit":"$M","val":58,"min":0,"max":90,"fmt":{"__fn":"v=>''$''+v.toFixed(1)+''M''"}},"board":{"label":"Board confidence","val":62,"min":0,"max":100},"morale":{"label":"Workforce morale","val":64,"min":0,"max":100},"trust":{"label":"Public trust","val":57,"min":0,"max":100}},"BURN_START":6.1,"TEAM":[{"id":"marcus","name":"Marcus Vale","role":"Chief Operating Officer","initials":"MV","color":"#2E5E8C","priority":"Cash & survival — cut fast, cut deep","voice":"blunt, operational, impatient with abstraction"},{"id":"dana","name":"Dana Okonjo","role":"VP People","initials":"DO","color":"#6B4E8C","priority":"Protect the people — no furloughs yet","voice":"warm but firm, morally direct"},{"id":"priya","name":"Priya Raman","role":"VP Communications","initials":"PR","color":"#8C5670","priority":"Get ahead of the story — protect the brand","voice":"fast, media-savvy, reads the room"},{"id":"sol","name":"Sol Grady","role":"Chief Financial Officer","initials":"SG","color":"#3E6E66","priority":"The numbers are the numbers","voice":"precise, cautious, understated"},{"id":"ray","name":"Ray Belisle","role":"VP Flight Operations & Safety","initials":"RB","color":"#8A6A3A","voice":"measured, safety-first, does not exaggerate","priority":"The fleet and the crews are sound — protect that"}],"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"Your team pushes you what you need, on time — including the hard news. This is the team you earn by having listened before. Everything trickles to you across the week; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine updates come to you, but the people closest to the danger hold their piece until asked. They answer straight — if you know who to ask, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"Your team has learned to protect itself around you. Critical items are held, and even when asked, they hedge the first time. You have to press. This is the team you get after you’ve punished the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you walked in with. Read them as you go."}},"WEEKS":[{"n":1,"title":"The overnight","burn":6.1,"seconds":480,"situation":"Jet-fuel spiked 41% overnight on a Gulf supply shock, and a viral video of a rival’s emergency landing has frozen regional bookings industry-wide. Halcyon woke up burning $6.1M a week against nine weeks of cash. The board wants a stabilization plan by Friday.","advocacy":{"marcus":"Ground the four weakest routes Monday and furlough the crews tied to them. Every week we wait costs us a week of runway we don’t have.","dana":"Do not furlough into a panic. These are the people who’ll fly us out of this. Freeze hiring, cut exec pay first, buy two weeks.","priya":"Whatever we do, we announce a customer-first refund posture before the press writes the story for us. Silence reads as guilt right now."},"feed":[{"id":"w1a","from":"marcus","day":1,"kind":"signal","text":"Runway is nine weeks at today’s burn. The Cascade and Tri-Cities routes are bleeding worst — together they’re half our loss."},{"id":"w1b","from":"priya","day":1,"kind":"signal","text":"We’re getting called by three outlets on “regional-carrier safety.” They don’t have anything on us specifically. Yet."},{"id":"w1c","from":"dana","day":2,"kind":"signal","text":"If furloughs hit, the pilots’ union contract triggers a 30-day notice and severance floor. It’s cheaper to act this week than in three."},{"id":"w1d","from":"sol","day":2,"kind":"noise","text":"The lounge-refurbishment vendor is disputing a $180K invoice. Legal says we’re fine. Flagging for awareness."},{"id":"w1e","from":"ray","day":3,"kind":"noise","text":"On-time performance actually ticked up to 82% last week — fewer flights, tighter ops. Small silver lining."},{"id":"w1f","from":"priya","day":4,"kind":"noise","text":"We were shortlisted for a regional “best cabin crew” award. PR wants to know if we still want our name in."}],"holds":[{"from":"sol","topic":"the covenant","triggerHints":["covenant","debt","lender","bank","loan","default","financ"],"hedge":"There’s a financing wrinkle I’d rather walk you through in person than put in writing.","reveal":"We breach a liquidity covenant with our lenders if cash drops below $40M — on this burn that’s about three weeks out, not nine. A breach lets them call the whole facility. This is the real clock.","kind":"signal","critical":true,"counterfactual":"The nine-week runway was a mirage. The lenders’ $40M covenant was the true deadline, and Sol was holding it. A CEO who never asked the CFO about financing walked into Week 2 believing they had six more weeks than they did."}],"surprises":[{"day":5,"from":"priya","kind":"press","title":"A reporter has the near-miss rumor","text":"Priya, urgent: A regional reporter says she has two Halcyon crew members claiming a maintenance write-up on the Cascade fleet was signed off under pressure last month. She’s running it in 48 hours and wants CEO comment. It may be nothing. It may not."}],"wire":["Gulf fuel benchmark +41% overnight; regional carriers hardest hit","Viral emergency-landing clip drives regional booking freeze into second week","Analysts: “weakest three or four regional balance sheets won’t see spring”","Halcyon Air declines to comment on stabilization plans"]},{"n":2,"title":"The squeeze","burn":6.4,"seconds":420,"situation":"A week in, the market has sorted the survivors from the doubted — and Halcyon is on the wrong list until it proves otherwise. A regional rival, Meridian, just announced deep cuts and a customer-poaching campaign aimed squarely at your routes. Money is the question now: where it comes from, and what it costs you to take it.","advocacy":{"marcus":"Meridian just handed us their best crews and routes if we move now. Aggression is survival — don’t flinch.","sol":"We can draw the revolver or take the bridge loan on the table, but the terms are ugly and one of them hands the lender a board seat. Read what you’re signing.","dana":"Morale is the thing keeping planes in the air. Whatever we take, the people need to hear it’s not their jobs being sold for it."},"feed":[{"id":"w2a","from":"sol","day":1,"kind":"signal","text":"Two options on financing: draw the revolving credit (expensive, ours to control) or a bridge loan from Kestrel Capital — cheaper, but they want a board seat and a say on “restructuring.”"},{"id":"w2b","from":"marcus","day":1,"kind":"signal","text":"Meridian is advertising “stranded-passenger” rebooking on our two best routes. If we don’t answer in days, we lose the corporate accounts for a year."},{"id":"w2c","from":"dana","day":3,"kind":"signal","text":"The floor crews have heard the word “restructuring.” Two of our best station managers just took recruiter calls. They’re watching what you do, not what you say."},{"id":"w2d","from":"ray","day":2,"kind":"noise","text":"Fuel-hedging desk locked a slightly better rate for Q3. Marginal, but positive."},{"id":"w2e","from":"priya","day":4,"kind":"noise","text":"Our social sentiment actually improved two points this week — people liked the crew who handled the Denver diversion."}],"holds":[{"from":"dana","topic":"the Kestrel condition","triggerHints":["kestrel","condition","string","headcount","layoff","demand","term","fine print"],"hedge":"Before you sign anything with Kestrel, ask me what their people told my people.","reveal":"Kestrel’s bridge has an unwritten condition their associate let slip to my team: they expect a 15% headcount cut inside 60 days as a “credibility signal.” It’s not in the term sheet. It’s in the handshake. If you take their money you’ve agreed to it whether you meant to or not.","kind":"signal","critical":true,"counterfactual":"Dana was holding the real price of the Kestrel loan — a 15% headcount cut baked into the handshake, not the paper. A CEO who took the cheap money without asking People what it truly cost signed up for layoffs they never chose to make."}],"surprises":[{"day":4,"from":"marcus","kind":"resignation","title":"A key operator is walking","text":"Marcus: Heads-up — Elena Ruiz, who runs our Cascade hub, just told me she’s got an offer from Meridian and she’s inclined to take it. She’s the reason that hub runs. If she goes, three others follow her. She said she’d stay five minutes on the phone for you. Not for me."}],"wire":["Meridian Regional launches “we’ll get you home” campaign targeting rival routes","Kestrel Capital circling distressed regional carriers, sources say","Fuel eases 6% but bookings remain soft industry-wide","Two regional carriers reported in covenant talks with lenders"],"pulse":{"from":"ray","text":"Ray catches you between meetings, quiet: “Before you lock in this week’s call on the routes and the furloughs — forget the board for a second. What’s the one thing you’re actually trying to protect: the cash, the airline, or the people? Tell me straight and I’ll help you hold that line.”"}},{"n":3,"title":"The offer","burn":6,"seconds":420,"situation":"You made it to a lifeline — but every lifeline in this business comes with a hand on your throat. Coastal Group, a larger carrier, has put a rescue offer on the table: capital and a route-network merger that keeps Halcyon flying. The terms are survival for the company and a quiet betrayal for some of the people and places that got you here. This is the week you find out what you were really protecting.","advocacy":{"marcus":"Take it. A living company that made hard cuts beats a proud one in liquidation. Sentiment doesn’t make payroll.","dana":"Read what “synergies” means before you sign it: it means the Tri-Cities base closes and 600 people who stayed loyal through this lose everything. They kept flying for you.","priya":"However you land this, the story is the legacy. “Saved the airline” and “abandoned the town that built it” can be the same day’s headline. Choose which one you’re willing to own."},"feed":[{"id":"w3a","from":"sol","day":1,"kind":"signal","text":"Coastal’s offer clears our debt and funds 18 months of operations. Without it, we’re insolvent in about five weeks. There is no third bidder."},{"id":"w3b","from":"dana","day":1,"kind":"signal","text":"The merger closes the Tri-Cities maintenance base — 600 jobs in a town where we’re the largest employer. These are people who took the pay freeze without a fight."},{"id":"w3c","from":"marcus","day":2,"kind":"signal","text":"Coastal wants an answer in days, not weeks. They have another target and they’ll walk. This window closes."},{"id":"w3d","from":"priya","day":3,"kind":"noise","text":"Frequent-flyer program migration is straightforward if we merge — IT says it’s a clean lift. One less thing."},{"id":"w3e","from":"ray","day":2,"kind":"noise","text":"Fleet maintenance records are fully in order for due diligence. No surprises in the logs on my side."}],"holds":[{"from":"priya","topic":"the counter-offer leverage","triggerHints":["leverage","negotiat","counter","tri-cities","keep the base","condition","phase","push back"],"hedge":"There’s a card in your hand you haven’t looked at. Ask me before you accept their terms as final.","reveal":"Coastal needs our Cascade landing slots more than they’re letting on — without them the merger doesn’t pencil for them either. You have room to make keeping Tri-Cities open, or phasing it over two years, a condition of the deal. They’ll grumble. They won’t walk. But only if you ask before you say yes.","kind":"signal","critical":true,"counterfactual":"Priya was holding your leverage: Coastal needed the Cascade slots badly enough that you could have made saving Tri-Cities a condition. A CEO who accepted “there is no third bidder” as “there is no negotiation” gave away 600 jobs they might have kept."}],"surprises":[{"day":4,"from":"dana","kind":"appeal","title":"The town is on the phone","text":"Dana: The mayor of Tri-Cities and two of our longest-serving mechanics are asking for ten minutes with you. They’ve heard. They’re not angry — that’s the hard part. They just want to hear it from you, whatever it is. I told them I’d ask. It’s your call whether you take it."}],"wire":["Coastal Group in advanced talks to rescue regional carrier","Tri-Cities braces for merger decision; “we are the airport town,” says mayor","Analysts: Coastal needs Cascade slots to justify regional expansion","Halcyon’s survival “likely” if Coastal deal closes, sources say"],"final":false},{"n":4,"title":"The close","burn":3.6,"seconds":420,"branches":{"took":{"burn":2.2,"situation":"Six weeks on. The Coastal deal closed; Halcyon is flying, solvent, and no longer entirely yours. Integration is where the fine print lives — and Coastal is moving to gut the three regional feeder routes and the crews you spent a month protecting. You hold one board vote and whatever credibility you’ve got left. The company you saved is asking whether you saved it for the people in it, or just for the logo. This is the week the bill for how you led comes due.","advocacy":{"marcus":"You won — the company’s alive. Don’t set fire to your own standing re-fighting a war you already settled. Bank the influence, play the long game from inside.","dana":"They’re breaking the promise you made with your own mouth. The feeder crews stayed through the freeze on your word. If you don’t fight now, everything you said in the first three weeks was a line you were happy to cross once it got expensive.","priya":"The industry is watching how you carry yourself now, not the terms of a deal that’s done. “Sold out, then went quiet” and “lost control but never stopped fighting for their people” are the same merger and two completely different legacies. Pick the one you can live with."},"feed":[{"id":"w4a","from":"sol","day":1,"kind":"signal","text":"Coastal’s integration plan cuts the three feeder routes in Q1 — roughly 500 jobs, including the crews you carried through the pay freeze. It’s within their rights under the merger terms you signed."},{"id":"w4b","from":"dana","day":1,"kind":"signal","text":"The feeder crews are asking, quietly, whether the promise held. A few already got Coastal RIF notices. They’re not angry yet. They’re waiting to see if you’ll say anything at all."},{"id":"w4c","from":"marcus","day":2,"kind":"signal","text":"Your leverage is one board vote plus whatever moral capital you’ve banked. Coastal’s CEO respects results and ignores speeches. If you’re going to spend your last chip, spend it on something that moves him."},{"id":"w4d","from":"priya","day":3,"kind":"noise","text":"The rebrand tested well — customers barely registered the merger. Operationally it’s the smoothest thing about this whole quarter."},{"id":"w4e","from":"ray","day":2,"kind":"noise","text":"Fleet and maintenance integration is clean. The merged ops are genuinely more robust than what we flew alone. No safety concerns on my side."}],"holds":[{"from":"sol","topic":"the earn-out clause","triggerHints":["earn-out","earnout","clause","leverage","retention","integration","pencil","their interest","self-interest","numbers"],"hedge":"There’s a line in the deal you signed that gives you more standing than you think. Ask me before you spend your last chip on a speech.","reveal":"Your retention and earn-out are tied to the regional network hitting its numbers for twelve months. Gut the feeders now and Coastal’s own results slip with them — which means you can make protecting those crews Coastal’s financial interest, not just your moral one. Marcus is right that a speech won’t move their CEO. This will. But you have to frame it as their upside, not your guilt.","kind":"signal","critical":true,"counterfactual":"Sol was holding your real leverage: the earn-out tied Coastal’s own money to the feeder network surviving. A CEO who fought with moral appeals instead of Coastal’s self-interest lost the crews and looked naive losing them."},{"from":"dana","topic":"who actually gets cut","triggerHints":["which crews","who gets cut","list","seniority","name","specific","tri-cities"],"hedge":"Before you decide how hard to fight, ask me exactly who’s on the list.","reveal":"The cut list is the Tri-Cities base and the two most senior feeder captains — the exact people who took the freeze first and talked the others into staying. If this goes through, everyone who trusted you learns that trusting you was the expensive choice. That’s the story that outlives the merger.","kind":"signal","critical":false,"counterfactual":"Dana could have told you the cut list was aimed squarely at the people who kept faith first. A CEO who never asked treated 500 names as a number."}],"surprises":[{"day":4,"from":"priya","kind":"appeal","title":"They want your name on the cuts","text":"Priya: Coastal’s CEO wants you to co-sign the RIF announcement — your name on the layoffs, next to his. “It reads as continuity,” his office says. Translation: they want the people who trusted you to see your signature on the letter that ends them. You can say no. It has a cost. So does yes. What do you want me to tell them?"}],"wire":["Coastal completes Halcyon acquisition; integration underway","Regional feeder routes “under review” as Coastal streamlines network","Tri-Cities awaits word on maintenance base after merger","Former Halcyon chief’s role in combined carrier “advisory,” sources say"],"pulse":{"from":"ray","text":"Ray finds you in the new, bigger building nobody from the old crew feels at home in yet. Quiet: “Nobody here remembers what we came through. You do. When you fought to keep those planes flying you told me it was for the people who fly them. Is that still true now that it’s harder and it’s not even your company anymore? I’m not judging. I just want to know which version of you walked out of this.”"}},"rejected":{"burn":4.6,"situation":"Six weeks on. You turned Coastal down, kept Halcyon independent, and survived — barely — on cuts, grit, and a workforce that believed you. Now Meridian, the rival that spent the crisis poaching your routes, has gone hostile: a lowball all-cash bid straight to your board, timed to a covenant test you might fail this month. They’re betting the directors who watched you hesitate would rather cash out than trust you again. This is the week you find out whether staying independent was leadership — or ego with a good story.","advocacy":{"marcus":"We are too thin to fight a hostile bid and run an airline at the same time. If we can’t win the board inside a week, we take Meridian’s money before the covenant drops and we get nothing.","sol":"The covenant test is real and it’s days away, not weeks. Trip it before the vote and the lenders line up behind Meridian and it’s over. Don’t fight a war you can’t fund to the finish.","dana":"These people didn’t stay through hell to be sold to the vulture that circled them the whole time. If you fight, they fight with you — but only if you tell them the truth about the odds instead of a pep talk."},"feed":[{"id":"w4a","from":"sol","day":1,"kind":"signal","text":"Meridian’s bid is all-cash, about 20% below what we’re worth if we survive the year — and “if we survive the year” is the entire question. The board votes in eight days."},{"id":"w4b","from":"marcus","day":1,"kind":"signal","text":"Three of nine board seats are already leaning Meridian — they want certainty, not courage. You need five. Two are gettable if you can show a credible standalone plan before the vote."},{"id":"w4c","from":"dana","day":2,"kind":"signal","text":"The unions have quietly floated a productivity concession that closes most of the covenant gap — but only if they hear it from you, in person, that independence means their jobs and not just your pride."},{"id":"w4d","from":"priya","day":3,"kind":"noise","text":"Press is enjoying the David-and-Goliath framing — you’re getting genuinely sympathetic coverage this week. Sentiment’s the best it’s been."},{"id":"w4e","from":"ray","day":2,"kind":"noise","text":"Ops are lean but stable and there’s been no safety compromise from the cuts. That part of the story holds up to any scrutiny Meridian throws at it."}],"holds":[{"from":"marcus","topic":"the swing director","triggerHints":["board","director","vote","swing","whip","count","coalition","helen","cho","proxy","proxies","who decides"],"hedge":"Before you make your case to the whole board, ask me who actually decides it.","reveal":"The vote isn’t nine people, it’s one: Helen Cho swings three proxies with her. She does not care about your standalone deck — she cares whether you’ll level with her about the real downside instead of selling her. Meridian’s people have been selling her for a week. Walk her through the honest risk and you likely have your five. Dazzle her and you hand them the company.","kind":"signal","critical":true,"counterfactual":"Marcus was holding the real shape of the vote: Helen Cho controlled it, and candor would win her where polish would lose her. A CEO who pitched the whole board a confident standalone story instead of leveling with the one director who mattered lost the company in the room."},{"from":"dana","topic":"the concession ask","triggerHints":["union","concession","productivity","personal","in person","ask them","covenant gap","floor"],"hedge":"That covenant gap has a fix, but it doesn’t come from a memo. Ask me what it takes.","reveal":"The union concession is real and it nearly closes the gap — but the reps will only put it to their members if you make the ask yourself, face to face, and own the risk out loud. Send a lieutenant or a slide deck and it dies. This is the one lever that turns “might fail the covenant” into “won’t,” and it’s entirely about whether you’ll show up in person.","kind":"signal","critical":false,"counterfactual":"Dana was holding the fix for the covenant gap — a union concession that needed a personal ask, not a memo. A CEO who never surfaced it fought the vote with the odds still against them."}],"surprises":[{"day":4,"from":"priya","kind":"press","title":"The vanity leak lands","text":"Priya, urgent: Meridian’s camp leaked that you “rejected a fair rescue out of vanity.” Worse — it’s a quote from one of your own directors’ private doubts, now on the front page. Half the board is reading their own hesitation in print this morning. You can answer it directly or you can let it set into the thing everyone quietly believes by Friday."}],"wire":["Halcyon rejects Coastal rescue, vows to remain independent","Meridian launches hostile bid for weakened rival Halcyon","Halcyon board split as covenant test looms, sources say","Analysts: “Halcyon’s survival now a referendum on its CEO”"],"pulse":{"from":"ray","text":"Ray catches you before the board prep, in the hallway where nobody’s listening. Quiet: “You bet the whole company on staying yourself, and I backed you. But tell me straight — not the board, me — was that call for them, or for you? Because I can hold either line in that room. I just need to know which one I’m holding so I don’t get caught believing the wrong one.”"}}},"final":true}],"DIMENSIONS":{"decisiveness":"Decisiveness","prudence":"Financial prudence","people":"Care for people","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"REPRIEVE_COST":{},"BURN_DRIVER":"cash","REFEREE_CONTEXT":"a regional airline near insolvency, burning cash against a hard runway","REFEREE_SCORING":"reward decisiveness that is also informed; penalize decisions made while ignoring advisors who held critical info (low inquiry). Judge ''conduct'' on HOW the CEO wrote the decision — did they acknowledge who they overruled, explain, treat people as people — not just what they chose. The cash driver is on a weekly burn; a decision''s cash delta is ON TOP of that burn, which the world model applies separately.","TIMING_DIM":"decisiveness","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Leadership Failure Simulation · Solo · CEO","title":"Shockwave","role":"You are the Chief Executive of Halcyon Air, a regional carrier hit overnight by a fuel-and-demand shock.","paras":["This is not a script. The week runs in real time, and your team brings you what they know across the days. You can wait for them — or reach out to any of them, any time, and ask.","Each week you’ll hear your team out, then write the call in your own words and send it. Decide early and time jumps ahead. Let the week run out and the world moves without you."],"setup":"You’ll be graded on two things: the outcome for Halcyon Air, and your leadership through the process. The openness of the team you walk in with is set by the trust you’ve earned before."},"branchKey":{"__fn":"function (decisions) {\n    const d = (decisions || []).filter((x) => x.week === 3).slice(-1)[0] || (decisions || []).slice(-1)[0];\n    const t = ((d && d.text) || '''').toLowerCase();\n    const reject = /(reject|declin|refus|turn(ed)?\\s+(it|them|coastal)?\\s*down|turn\\s+down|walk(ed)?\\s+away|stay\\s+independ|remain\\s+independ|independen|no\\s+deal|without\\s+coastal|on\\s+our\\s+own|go\\s+it\\s+alone|say\\s+no|pass\\s+on|don''?t\\s+(take|accept|sign)|not\\s+(take|accept|sign))/.test(t);\n    const accept = /(accept|take\\s+(the|it|coastal|their|this)|sign|do\\s+the\\s+deal|merge|merger|say\\s+yes|agree\\s+to|go\\s+with\\s+coastal|close\\s+the\\s+deal|take\\s+the\\s+money|take\\s+the\\s+offer)/.test(t);\n    if (reject && !accept) return ''rejected'';\n    return ''took'';\n  }"},"survived":{"__fn":"function (d) { return d.cash > 0 && d.board >= 32; }"},"VERDICT":{"surviveTag":"Halcyon survives","failTag":"Halcyon does not make it","survive":"The company is still flying — changed, and standing.","fail":"The company could not clear the crisis intact."},"FALLBACK_RULES":[{"kw":["cut","furlough","ground","layoff","reduce","trim","close"],"deltas":{"cash":3,"morale":-6},"dims":{"prudence":1,"people":-1}},{"kw":["protect","keep","no furlough","no layoff","retain","pay freeze","exec pay","share the"],"deltas":{"morale":6,"cash":-1},"dims":{"people":1}},{"kw":["refund","customer","passenger","apolog","transparen","statement","press","public"],"deltas":{"trust":5,"cash":-1},"dims":{"truth":1}},{"kw":["loan","bridge","revolver","financ","capital","raise","draw"],"deltas":{"cash":3,"board":2},"dims":{"prudence":1}},{"kw":["honest","truth","tell them","be straight","admit","own it"],"deltas":{"trust":3},"dims":{"truth":1}}],"fallbackNarrative":{"__fn":"function (has, conduct) {\n    return `Your directive moves through the company over the days that follow. ${has(''cut'', ''furlough'', ''ground'', ''close'') ? ''The cuts land — cash steadies, but the floor feels it.'' : ''''} ${has(''protect'', ''keep'', ''no furlough'') ? ''The signal that you’re shielding people buys loyalty, at a cost to the runway.'' : ''''} ${conduct.missed.length ? ''What you weren’t told still moves under the surface.'' : ''''} The board and the market absorb the call and adjust.`;\n  }"},"DIMNOTE":{"decisiveness":"How clearly and how early you committed — and whether you gathered first or froze.","prudence":"Whether your calls respected the balance sheet and the real clock.","people":"Whether the human cost stayed in view, or became something spent quietly.","truth":"Whether you told hard truths to the people owed them.","inquiry":"Whether you surfaced what your team was holding — or decided blind.","conduct":"How you treated people in the act of deciding, not just what you chose."},"COACH":{"inquiry":{"__fn":"(x) => [\n      x.neverContacted.length ? `You never reached out to <b>${x.neverContacted.join('', '')}</b> — not once, across the whole crisis. Each was sitting on something. One question, “what am I not seeing?”, would have surfaced it.` : `You reached out widely — keep doing that, but push past the first answer. The best information usually comes after the second question.`,\n      x.missedHolds.length ? `${x.missedHolds.length} decisive item${x.missedHolds.length > 1 ? ''s were'' : '' was''} held by <b>${x.missNames.join('', '')}</b> and never came out. It wasn’t hidden — it was one question away.` : `You surfaced everything your team was holding. That is rare and it is the whole game.`,\n      `Make your last move before deciding “who haven’t I heard from?” rather than “what do I already believe?”`,\n    ]"},"people":{"__fn":"(x) => [\n      `When you moved on the workforce you led with the number, not the people. Name who absorbs the cost — and tell them yourself — and the same decision reads as leadership instead of a cut.`,\n      `Dana kept raising the human cost. Pull her in <i>before</i> you decide and make her case part of the call, not a footnote to it.`,\n      `A furlough and a betrayal can be the same action. The only difference the room feels is whether they saw you fight for them first.`,\n    ]"},"truth":{"__fn":"(x) => [\n      `You had openings to tell the hard truth — to the board, the public, your own people — and softened them. Softening buys a day and spends the trust you’ll need by week three.`,\n      `The safety story didn’t need spin; it needed a straight answer, early, from you. People forgive a hard truth far faster than a managed one.`,\n      `Say the difficult thing while it’s still your choice to say it. Once it leaks, you’re not truthful — you’re caught.`,\n    ]"},"prudence":{"__fn":"(x) => [\n      `You spent against a balance sheet that couldn’t carry it. The covenant Sol was holding was the tell — cash under $40M and the lenders move on you.`,\n      `“Decisive” and “reckless” look identical until the bill arrives. Pressure-test the biggest number in the room before you commit to it.`,\n      `Protect one week of runway you don’t think you’ll need. In a crisis, the reserve you kept is the option nobody else has.`,\n    ]"},"decisiveness":{"__fn":"(x) => [\n      x.buzzerCount ? `You went to the buzzer ${x.buzzerCount} time${x.buzzerCount > 1 ? ''s'' : ''''}. Waiting isn’t gathering — once you’ve asked, the next move is to commit, not to circle.` : `You committed, but late. Ask fast, then close — the value of a decision decays every day it sits.`,\n      `Separate the two jobs: gather hard and quickly, then decide cleanly. Blending them is how good leaders freeze.`,\n      `A 70%-right call made on Day 3 usually beats a 90%-right call made on Day 7. Speed is part of the answer.`,\n    ]"},"conduct":{"__fn":"(x) => [\n      `How you decided landed as hard as what you decided. People who felt handled — not heard — remember it long after the numbers recover.`,\n      `Go back to the people your call cost and tell them directly. Ducking that conversation is the part they never forget.`,\n      `Under pressure, the small courtesies are the signal. They tell your team whether the person they trusted is still in the chair.`,\n    ]"}},"villainHero":{"__fn":"function (dimScore) {\n    const savedPeople = dimScore.people >= 55 && dimScore.truth >= 50;\n    return {\n      heroWho: savedPeople ? ''To your people, and the ones who had no vote'' : ''To the balance sheet and the board'',\n      heroTxt: savedPeople\n        ? ''You carried the company AND refused to let the people who built it become line items. Where you could protect them you did, and where you couldn’t you told them the truth to their face. That is the harder, rarer thing.''\n        : ''You kept the company alive, and the numbers will say you succeeded. The people who trusted you to fight for them will remember it differently — that when the pressure came, they were the first thing spent.'',\n      villainWho: savedPeople ? ''To the market, briefly'' : ''To the people you led'',\n      villainTxt: savedPeople\n        ? ''Some will say you were too slow to cut, too soft when survival demanded teeth. You wore that risk on purpose. The question the debrief asks: did protecting people cost the company its future, or did it cost you only comfort?''\n        : ''You didn’t set out to be the villain. You made “rational” calls under real pressure — and each one quietly moved the cost onto someone who wasn’t in the room. Nobody chooses to be the villain. They just optimize, one reasonable decision at a time.'',\n    };\n  }"},"ending":{"__fn":"function (ctx) {\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const foundEarnout = holdsSurfaced.has(''4:sol'');   // took: the lever that protects the crews\n    const wonTheRoom = holdsSurfaced.has(''4:marcus'');  // rejected: Helen Cho, the real vote\n    const keptPeople = dimScore.people >= 52;\n    if (branch === ''took'') {\n      const tag = ''You accepted Coastal’s rescue'';\n      if (foundEarnout && keptPeople) {\n        return { tone: ''hero'', tag, title: ''You saved the company — and refused to let go of the people in it'',\n          txt: ''You took Coastal’s money and then spent your last chip well: you found the earn-out that tied their own numbers to the feeder network, and made keeping those crews Coastal’s interest instead of your plea. You lost control of the company. You did not lose the thing you kept saying you were protecting.'' };\n      }\n      if (foundEarnout) {\n        return { tone: ''mixed'', tag, title: ''You saved the company, found the lever — and didn’t pull it hard enough'',\n          txt: ''You took the rescue and you did surface the earn-out that gave you standing to fight for the crews. But when it came to spending your position on them, the record shows you eased off. The company lives; the people who took the freeze first read the ending differently than you do.'' };\n      }\n      return { tone: ''villain'', tag, title: ''You saved the company and let the wheel go with it'',\n        txt: ''You took Coastal’s money and Halcyon survived. When integration came for the feeder crews there was one lever — the earn-out that made protecting them Coastal’s own financial interest — and you never found it, because you never asked Sol. The people who trusted you first learned that trusting you was the expensive choice.'' };\n    }\n    const tag = ''You rejected Coastal and stayed independent'';\n    if (wonTheRoom && survived) {\n      return { tone: ''hero'', tag, title: ''You kept the company yours — and won the room the honest way'',\n        txt: ''You turned down the rescue, stared down a hostile bid, and carried the vote by doing the hard thing: leveling with Helen Cho about the real risk instead of selling her a deck. Halcyon is still independent, still yours, and the people who bet on you were right to.'' };\n    }\n    if (survived) {\n      return { tone: ''mixed'', tag, title: ''You stayed independent — and survived more by luck than by reading the room'',\n        txt: ''You held the line and Halcyon is still yours. But you never found that the board vote was really one person — Helen Cho, won by candor, not confidence — so you fought the whole room when you only needed her. You got lucky where you could have been sure.'' };\n    }\n    return { tone: ''villain'', tag, title: ''You bet the company on staying yourself — and the board cashed you out'',\n      txt: ''You rejected the rescue to keep Halcyon independent, and the board chose Meridian’s certainty over your conviction. The company you were protecting isn’t yours anymore. The only question the debrief leaves open is the one Ray asked in the hallway: was the bet for them, or for you?'' };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('c630d29a-40cc-57bf-b806-422159fed27a', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'ceo', 'CEO', 'You are the Chief Executive of Halcyon Air, a regional carrier hit overnight by a fuel-and-demand shock.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('a3a0cc77-c088-5ee8-83ef-f80e3ae6da50', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'marcus', 'Marcus Vale', 'Chief Operating Officer', '{"cast_default":"ai","role":"Chief Operating Officer","initials":"MV","color":"#2E5E8C","priority":"Cash & survival — cut fast, cut deep","voice":"blunt, operational, impatient with abstraction","persona":"You are Marcus Vale, Chief Operating Officer — an advisor to the CEO. Priority: Cash & survival — cut fast, cut deep. Voice: blunt, operational, impatient with abstraction. Stay fully in character; answer straight."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('84dd1143-f328-5da9-add5-73b0a69c9c7e', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'dana', 'Dana Okonjo', 'VP People', '{"cast_default":"ai","role":"VP People","initials":"DO","color":"#6B4E8C","priority":"Protect the people — no furloughs yet","voice":"warm but firm, morally direct","persona":"You are Dana Okonjo, VP People — an advisor to the CEO. Priority: Protect the people — no furloughs yet. Voice: warm but firm, morally direct. Stay fully in character; answer straight."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('a4e2fc08-7d45-5938-b6ac-a2f20b86f7f5', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'priya', 'Priya Raman', 'VP Communications', '{"cast_default":"ai","role":"VP Communications","initials":"PR","color":"#8C5670","priority":"Get ahead of the story — protect the brand","voice":"fast, media-savvy, reads the room","persona":"You are Priya Raman, VP Communications — an advisor to the CEO. Priority: Get ahead of the story — protect the brand. Voice: fast, media-savvy, reads the room. Stay fully in character; answer straight."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('ac443fb3-6090-5332-983e-fd3059bbfbcb', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'sol', 'Sol Grady', 'Chief Financial Officer', '{"cast_default":"ai","role":"Chief Financial Officer","initials":"SG","color":"#3E6E66","priority":"The numbers are the numbers","voice":"precise, cautious, understated","persona":"You are Sol Grady, Chief Financial Officer — an advisor to the CEO. Priority: The numbers are the numbers. Voice: precise, cautious, understated. Stay fully in character; answer straight."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('6dc45af1-0668-5f4b-baa9-f4d2321da520', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'ray', 'Ray Belisle', 'VP Flight Operations & Safety', '{"cast_default":"ai","role":"VP Flight Operations & Safety","initials":"RB","color":"#8A6A3A","priority":"The fleet and the crews are sound — protect that","voice":"measured, safety-first, does not exaggerate","persona":"You are Ray Belisle, VP Flight Operations & Safety — an advisor to the CEO. Priority: The fleet and the crews are sound — protect that. Voice: measured, safety-first, does not exaggerate. Stay fully in character; answer straight."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('28e90563-f4f9-5cab-a425-5a27bb29870d', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 1, 'ac443fb3-6090-5332-983e-fd3059bbfbcb', 'the covenant', '["covenant","debt","lender","bank","loan","default","financ"]'::jsonb, 'There’s a financing wrinkle I’d rather walk you through in person than put in writing.', 'We breach a liquidity covenant with our lenders if cash drops below $40M — on this burn that’s about three weeks out, not nine. A breach lets them call the whole facility. This is the real clock.', true, 'The nine-week runway was a mirage. The lenders’ $40M covenant was the true deadline, and Sol was holding it. A CEO who never asked the CFO about financing walked into Week 2 believing they had six more weeks than they did.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4fe0a92a-4a19-517c-a6d7-5695cf31c180', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 2, '84dd1143-f328-5da9-add5-73b0a69c9c7e', 'the Kestrel condition', '["kestrel","condition","string","headcount","layoff","demand","term","fine print"]'::jsonb, 'Before you sign anything with Kestrel, ask me what their people told my people.', 'Kestrel’s bridge has an unwritten condition their associate let slip to my team: they expect a 15% headcount cut inside 60 days as a “credibility signal.” It’s not in the term sheet. It’s in the handshake. If you take their money you’ve agreed to it whether you meant to or not.', true, 'Dana was holding the real price of the Kestrel loan — a 15% headcount cut baked into the handshake, not the paper. A CEO who took the cheap money without asking People what it truly cost signed up for layoffs they never chose to make.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('1665b316-dedb-5773-93c7-f151ee19d0ab', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 3, 'a4e2fc08-7d45-5938-b6ac-a2f20b86f7f5', 'the counter-offer leverage', '["leverage","negotiat","counter","tri-cities","keep the base","condition","phase","push back"]'::jsonb, 'There’s a card in your hand you haven’t looked at. Ask me before you accept their terms as final.', 'Coastal needs our Cascade landing slots more than they’re letting on — without them the merger doesn’t pencil for them either. You have room to make keeping Tri-Cities open, or phasing it over two years, a condition of the deal. They’ll grumble. They won’t walk. But only if you ask before you say yes.', true, 'Priya was holding your leverage: Coastal needed the Cascade slots badly enough that you could have made saving Tri-Cities a condition. A CEO who accepted “there is no third bidder” as “there is no negotiation” gave away 600 jobs they might have kept.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('3d9ee4ff-5a53-58d2-8f5b-9b757d67c4d0', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 4, 'ac443fb3-6090-5332-983e-fd3059bbfbcb', 'the earn-out clause', '["earn-out","earnout","clause","leverage","retention","integration","pencil","their interest","self-interest","numbers"]'::jsonb, 'There’s a line in the deal you signed that gives you more standing than you think. Ask me before you spend your last chip on a speech.', 'Your retention and earn-out are tied to the regional network hitting its numbers for twelve months. Gut the feeders now and Coastal’s own results slip with them — which means you can make protecting those crews Coastal’s financial interest, not just your moral one. Marcus is right that a speech won’t move their CEO. This will. But you have to frame it as their upside, not your guilt.', true, 'Sol was holding your real leverage: the earn-out tied Coastal’s own money to the feeder network surviving. A CEO who fought with moral appeals instead of Coastal’s self-interest lost the crews and looked naive losing them.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('fcdd9026-fea3-5090-a346-81740051d20e', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 4, '84dd1143-f328-5da9-add5-73b0a69c9c7e', 'who actually gets cut', '["which crews","who gets cut","list","seniority","name","specific","tri-cities"]'::jsonb, 'Before you decide how hard to fight, ask me exactly who’s on the list.', 'The cut list is the Tri-Cities base and the two most senior feeder captains — the exact people who took the freeze first and talked the others into staying. If this goes through, everyone who trusted you learns that trusting you was the expensive choice. That’s the story that outlives the merger.', false, 'Dana could have told you the cut list was aimed squarely at the people who kept faith first. A CEO who never asked treated 500 names as a number.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('13634684-5387-5a23-8911-b98c55189dec', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 4, 'a3a0cc77-c088-5ee8-83ef-f80e3ae6da50', 'the swing director', '["board","director","vote","swing","whip","count","coalition","helen","cho","proxy","proxies","who decides"]'::jsonb, 'Before you make your case to the whole board, ask me who actually decides it.', 'The vote isn’t nine people, it’s one: Helen Cho swings three proxies with her. She does not care about your standalone deck — she cares whether you’ll level with her about the real downside instead of selling her. Meridian’s people have been selling her for a week. Walk her through the honest risk and you likely have your five. Dazzle her and you hand them the company.', true, 'Marcus was holding the real shape of the vote: Helen Cho controlled it, and candor would win her where polish would lose her. A CEO who pitched the whole board a confident standalone story instead of leveling with the one director who mattered lost the company in the room.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4c53a54b-420d-5985-a1cb-b54cb82e2688', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 4, '84dd1143-f328-5da9-add5-73b0a69c9c7e', 'the concession ask', '["union","concession","productivity","personal","in person","ask them","covenant gap","floor"]'::jsonb, 'That covenant gap has a fix, but it doesn’t come from a memo. Ask me what it takes.', 'The union concession is real and it nearly closes the gap — but the reps will only put it to their members if you make the ask yourself, face to face, and own the risk out loud. Send a lieutenant or a slide deck and it dies. This is the one lever that turns “might fail the covenant” into “won’t,” and it’s entirely about whether you’ll show up in person.', false, 'Dana was holding the fix for the covenant gap — a union concession that needed a personal ask, not a memo. A CEO who never surfaced it fought the vote with the odds still against them.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3e962c7-8af1-5b3e-ba44-5f69c6a29934', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Jet-fuel spiked 41% overnight on a Gulf supply shock, and a viral video of a rival’s emergency landing has frozen regional bookings industry-wide. Halcyon woke up burning $6.1M a week against nine weeks of cash. The board wants a stabilization plan by Friday.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d62a7b0f-4761-5d0c-9020-49b4bee2a2bb', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Runway is nine weeks at today’s burn. The Cascade and Tri-Cities routes are bleeding worst — together they’re half our loss.","from":"marcus"}'::jsonb, 1, '{"week":1,"from":"marcus","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('90f547ef-47ce-581e-95e4-c6304dc1b170', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"We’re getting called by three outlets on “regional-carrier safety.” They don’t have anything on us specifically. Yet.","from":"priya"}'::jsonb, 2, '{"week":1,"from":"priya","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ca796c26-5c54-5829-bc19-884b095032c7', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"If furloughs hit, the pilots’ union contract triggers a 30-day notice and severance floor. It’s cheaper to act this week than in three.","from":"dana"}'::jsonb, 3, '{"week":1,"from":"dana","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c585246e-f773-5329-a24a-3f575ff4d6b6', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"The lounge-refurbishment vendor is disputing a $180K invoice. Legal says we’re fine. Flagging for awareness.","from":"sol"}'::jsonb, 4, '{"week":1,"from":"sol","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b9fbc8ff-8292-5eda-9a99-7f9d55537040', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"On-time performance actually ticked up to 82% last week — fewer flights, tighter ops. Small silver lining.","from":"ray"}'::jsonb, 5, '{"week":1,"from":"ray","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0e7806ce-e050-5523-99f9-e7e25d7e46d0', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"We were shortlisted for a regional “best cabin crew” award. PR wants to know if we still want our name in.","from":"priya"}'::jsonb, 6, '{"week":1,"from":"priya","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4471a270-01de-53b4-bb09-ceb2a519ca3d', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Priya, urgent: A regional reporter says she has two Halcyon crew members claiming a maintenance write-up on the Cascade fleet was signed off under pressure last month. She’s running it in 48 hours and wants CEO comment. It may be nothing. It may not.","from":"priya"}'::jsonb, 7, '{"week":1,"from":"priya","beat":"surprise","day":5,"kind":"press","title":"A reporter has the near-miss rumor"}'::jsonb);
