insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ec38b40f-8e23-563a-a04a-f287b5275a40', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"A week in, the market has sorted the survivors from the doubted — and Halcyon is on the wrong list until it proves otherwise. A regional rival, Meridian, just announced deep cuts and a customer-poaching campaign aimed squarely at your routes. Money is the question now: where it comes from, and what it costs you to take it.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9aa639bc-eddc-5a76-9fc4-30c82bfadac2', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Two options on financing: draw the revolving credit (expensive, ours to control) or a bridge loan from Kestrel Capital — cheaper, but they want a board seat and a say on “restructuring.”","from":"sol"}'::jsonb, 13, '{"week":2,"from":"sol","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b1febf22-c558-5737-828b-86f00c62b647', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Meridian is advertising “stranded-passenger” rebooking on our two best routes. If we don’t answer in days, we lose the corporate accounts for a year.","from":"marcus"}'::jsonb, 14, '{"week":2,"from":"marcus","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('670a404d-3ca7-5eb2-9334-6bd1c86d4fb6', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"The floor crews have heard the word “restructuring.” Two of our best station managers just took recruiter calls. They’re watching what you do, not what you say.","from":"dana"}'::jsonb, 15, '{"week":2,"from":"dana","beat":"feed","day":3,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('aee0f300-2e26-5694-a2e3-c7c3ef5ac394', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Fuel-hedging desk locked a slightly better rate for Q3. Marginal, but positive.","from":"ray"}'::jsonb, 16, '{"week":2,"from":"ray","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6d6e5206-dc3a-569b-a477-8fc0b9cbcbbe', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Our social sentiment actually improved two points this week — people liked the crew who handled the Denver diversion.","from":"priya"}'::jsonb, 17, '{"week":2,"from":"priya","beat":"feed","day":4,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6b81af39-e6a6-5853-8c87-5672746fe79f', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Marcus: Heads-up — Elena Ruiz, who runs our Cascade hub, just told me she’s got an offer from Meridian and she’s inclined to take it. She’s the reason that hub runs. If she goes, three others follow her. She said she’d stay five minutes on the phone for you. Not for me.","from":"marcus"}'::jsonb, 18, '{"week":2,"from":"marcus","beat":"surprise","day":4,"kind":"resignation","title":"A key operator is walking"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f2aefa3a-0ff6-5e4b-a7f3-1e0be1c21ca8', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Ray catches you between meetings, quiet: “Before you lock in this week’s call on the routes and the furloughs — forget the board for a second. What’s the one thing you’re actually trying to protect: the cash, the airline, or the people? Tell me straight and I’ll help you hold that line.”","from":"ray"}'::jsonb, 19, '{"week":2,"from":"ray","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('45c9cdf8-d572-51b4-989a-401841035fb4', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Meridian Regional launches “we’ll get you home” campaign targeting rival routes","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
