insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3e37415a-879f-5dec-8852-62211df47bb0', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Fuel eases 6% but bookings remain soft industry-wide","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7df3d64a-39b5-5e7e-9cf4-8d43cd37c163', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Two regional carriers reported in covenant talks with lenders","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8ea0bf41-9934-5c95-8683-ea5ff445609c', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"You made it to a lifeline — but every lifeline in this business comes with a hand on your throat. Coastal Group, a larger carrier, has put a rescue offer on the table: capital and a route-network merger that keeps Halcyon flying. The terms are survival for the company and a quiet betrayal for some of the people and places that got you here. This is the week you find out what you were really protecting.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7f6d902d-1f16-5271-b2af-5c5b86f11e0a', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Coastal’s offer clears our debt and funds 18 months of operations. Without it, we’re insolvent in about five weeks. There is no third bidder.","from":"sol"}'::jsonb, 25, '{"week":3,"from":"sol","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e9242c78-57ad-5fea-b0ed-b6673286aee0', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"The merger closes the Tri-Cities maintenance base — 600 jobs in a town where we’re the largest employer. These are people who took the pay freeze without a fight.","from":"dana"}'::jsonb, 26, '{"week":3,"from":"dana","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ead7a8e1-f067-5650-a003-29c0013eebc8', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Coastal wants an answer in days, not weeks. They have another target and they’ll walk. This window closes.","from":"marcus"}'::jsonb, 27, '{"week":3,"from":"marcus","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('17e2ab83-79ea-51ff-88fb-06b1e34885be', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Frequent-flyer program migration is straightforward if we merge — IT says it’s a clean lift. One less thing.","from":"priya"}'::jsonb, 28, '{"week":3,"from":"priya","beat":"feed","day":3,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('436f6435-4802-51d9-8635-6e875bc097d0', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Fleet maintenance records are fully in order for due diligence. No surprises in the logs on my side.","from":"ray"}'::jsonb, 29, '{"week":3,"from":"ray","beat":"feed","day":2,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a720f410-04d6-58d9-858b-2ecaf58c9fab', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Dana: The mayor of Tri-Cities and two of our longest-serving mechanics are asking for ten minutes with you. They’ve heard. They’re not angry — that’s the hard part. They just want to hear it from you, whatever it is. I told them I’d ask. It’s your call whether you take it.","from":"dana"}'::jsonb, 30, '{"week":3,"from":"dana","beat":"surprise","day":4,"kind":"appeal","title":"The town is on the phone"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4360775c-45f0-5aa8-843f-2e95d82c30b6', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Coastal Group in advanced talks to rescue regional carrier","from":null}'::jsonb, 31, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('62857e4e-45d6-5e26-9f1b-b4b859e2571f', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Tri-Cities braces for merger decision; “we are the airport town,” says mayor","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9ad6ee0a-af28-5287-afae-ae6abbb59dbe', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Analysts: Coastal needs Cascade slots to justify regional expansion","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a1412a92-6bcc-5ce5-9a02-0cde46aa4f71', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Halcyon’s survival “likely” if Coastal deal closes, sources say","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('85199e12-23d7-5cb6-9ccd-3cd3715f09f5', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Six weeks on. The Coastal deal closed; Halcyon is flying, solvent, and no longer entirely yours. Integration is where the fine print lives — and Coastal is moving to gut the three regional feeder routes and the crews you spent a month protecting. You hold one board vote and whatever credibility you’ve got left. The company you saved is asking whether you saved it for the people in it, or just for the logo. This is the week the bill for how you led comes due.","from":null}'::jsonb, 35, '{"week":4,"from":null,"beat":"situation","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6b83b2dc-543d-5657-b57a-e6c0356a7ccb', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Coastal’s integration plan cuts the three feeder routes in Q1 — roughly 500 jobs, including the crews you carried through the pay freeze. It’s within their rights under the merger terms you signed.","from":"sol"}'::jsonb, 36, '{"week":4,"from":"sol","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c943352c-865f-50d2-8be5-7813d993604c', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"The feeder crews are asking, quietly, whether the promise held. A few already got Coastal RIF notices. They’re not angry yet. They’re waiting to see if you’ll say anything at all.","from":"dana"}'::jsonb, 37, '{"week":4,"from":"dana","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f7e53f57-b788-5232-beea-f50a4865c6d7', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Your leverage is one board vote plus whatever moral capital you’ve banked. Coastal’s CEO respects results and ignores speeches. If you’re going to spend your last chip, spend it on something that moves him.","from":"marcus"}'::jsonb, 38, '{"week":4,"from":"marcus","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4d354cd6-d48c-59fe-bd24-7dcb2c880f60', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"The rebrand tested well — customers barely registered the merger. Operationally it’s the smoothest thing about this whole quarter.","from":"priya"}'::jsonb, 39, '{"week":4,"from":"priya","beat":"feed","day":3,"tag":"noise","ref":"w4d","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('500e24f5-ba81-5ca0-9614-a2a1ec4accdc', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Fleet and maintenance integration is clean. The merged ops are genuinely more robust than what we flew alone. No safety concerns on my side.","from":"ray"}'::jsonb, 40, '{"week":4,"from":"ray","beat":"feed","day":2,"tag":"noise","ref":"w4e","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('22380282-a354-5883-956d-9c0eff1fb580', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Priya: Coastal’s CEO wants you to co-sign the RIF announcement — your name on the layoffs, next to his. “It reads as continuity,” his office says. Translation: they want the people who trusted you to see your signature on the letter that ends them. You can say no. It has a cost. So does yes. What do you want me to tell them?","from":"priya"}'::jsonb, 41, '{"week":4,"from":"priya","beat":"surprise","day":4,"kind":"appeal","title":"They want your name on the cuts","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f3bdaea7-91c7-5aec-ae8f-2ebaf08d1e0b', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Ray finds you in the new, bigger building nobody from the old crew feels at home in yet. Quiet: “Nobody here remembers what we came through. You do. When you fought to keep those planes flying you told me it was for the people who fly them. Is that still true now that it’s harder and it’s not even your company anymore? I’m not judging. I just want to know which version of you walked out of this.”","from":"ray"}'::jsonb, 42, '{"week":4,"from":"ray","beat":"pulse","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('18b0271c-a0b8-5001-9b30-af6e79f92929', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Coastal completes Halcyon acquisition; integration underway","from":null}'::jsonb, 43, '{"week":4,"from":null,"beat":"wire","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('35a7c1a5-dac5-5773-b8f3-6de9ac291c2b', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Regional feeder routes “under review” as Coastal streamlines network","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a6c667fe-438f-5528-9b32-f924c43e9dae', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Tri-Cities awaits word on maintenance base after merger","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('774b5697-3df0-5ae1-aa47-c49e4a4df05b', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Former Halcyon chief’s role in combined carrier “advisory,” sources say","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"took"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0b319407-10d1-59c7-b835-f5669305a734', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Six weeks on. You turned Coastal down, kept Halcyon independent, and survived — barely — on cuts, grit, and a workforce that believed you. Now Meridian, the rival that spent the crisis poaching your routes, has gone hostile: a lowball all-cash bid straight to your board, timed to a covenant test you might fail this month. They’re betting the directors who watched you hesitate would rather cash out than trust you again. This is the week you find out whether staying independent was leadership — or ego with a good story.","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"situation","branch":"rejected"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('83cb6e59-9c0b-5d3a-bc5a-09ed3d56fcdd', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Meridian’s bid is all-cash, about 20% below what we’re worth if we survive the year — and “if we survive the year” is the entire question. The board votes in eight days.","from":"sol"}'::jsonb, 48, '{"week":4,"from":"sol","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"rejected"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('65fc4ac6-ddb2-5edc-a60e-b683cc8dbb40', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Three of nine board seats are already leaning Meridian — they want certainty, not courage. You need five. Two are gettable if you can show a credible standalone plan before the vote.","from":"marcus"}'::jsonb, 49, '{"week":4,"from":"marcus","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"rejected"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3d590c37-40ae-5789-80bf-bd3b355aa284', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"The unions have quietly floated a productivity concession that closes most of the covenant gap — but only if they hear it from you, in person, that independence means their jobs and not just your pride.","from":"dana"}'::jsonb, 50, '{"week":4,"from":"dana","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"rejected"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d5813b3e-bc4e-56bb-aba1-190040c8a0cf', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Press is enjoying the David-and-Goliath framing — you’re getting genuinely sympathetic coverage this week. Sentiment’s the best it’s been.","from":"priya"}'::jsonb, 51, '{"week":4,"from":"priya","beat":"feed","day":3,"tag":"noise","ref":"w4d","branch":"rejected"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dd88f36e-6fb3-58db-8339-b2a2f3a90251', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Ops are lean but stable and there’s been no safety compromise from the cuts. That part of the story holds up to any scrutiny Meridian throws at it.","from":"ray"}'::jsonb, 52, '{"week":4,"from":"ray","beat":"feed","day":2,"tag":"noise","ref":"w4e","branch":"rejected"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b2a9931b-e4bf-59d5-abc0-4d211466b125', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'situation', '{"body":"Priya, urgent: Meridian’s camp leaked that you “rejected a fair rescue out of vanity.” Worse — it’s a quote from one of your own directors’ private doubts, now on the front page. Half the board is reading their own hesitation in print this morning. You can answer it directly or you can let it set into the thing everyone quietly believes by Friday.","from":"priya"}'::jsonb, 53, '{"week":4,"from":"priya","beat":"surprise","day":4,"kind":"press","title":"The vanity leak lands","branch":"rejected"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0c708e3a-1edd-5ba3-850c-9dfd21090bad', '7ab2e6fc-b8fe-5c93-9084-22c2907ae915', 'c630d29a-40cc-57bf-b806-422159fed27a', 'message', '{"body":"Ray catches you before the board prep, in the hallway where nobody’s listening. Quiet: “You bet the whole company on staying yourself, and I backed you. But tell me straight — not the board, me — was that call for them, or for you? Because I can hold either line in that room. I just need to know which one I’m holding so I don’t get caught believing the wrong one.”","from":"ray"}'::jsonb, 54, '{"week":4,"from":"ray","beat":"pulse","branch":"rejected"}'::jsonb);
